import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-verify-email',
  templateUrl: './verify-email.component.html',
  styleUrls: ['./verify-email.component.css']
})
export class VerifyEmailComponent implements OnInit {
  message = '';
  success = false;
  loading = true;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private authService: AuthService
  ) {}

  ngOnInit() {
    const token = this.route.snapshot.queryParamMap.get('token');

    if (token) {
      this.authService.verifyEmail(token).subscribe({
        next: (response) => {
          this.loading = false;
          this.success = response.success;
          this.message = response.message;

          if (response.success) {
            setTimeout(() => {
              this.router.navigate(['/login']);
            }, 3000);
          }
        },
        error: (error) => {
          this.loading = false;
          this.success = false;
          this.message = error.error?.message || 'Verification failed.';
        }
      });
    } else {
      this.loading = false;
      this.success = false;
      this.message = 'Invalid verification token.';
    }
  }
}
<div class="auth-container">
  <div class="container">
    <div class="row justify-content-center">
      <div class="col-md-6">
        <div class="card auth-card">
          <div class="card-body text-center">
            <h2 class="mb-4">Email Verification</h2>

            <div *ngIf="loading">
              <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
              </div>
              <p class="mt-3">Verifying your email...</p>
            </div>

            <div *ngIf="!loading && success" class="alert alert-success">
              {{ message }}
              <p class="mt-2">Redirecting to login...</p>
            </div>

            <div *ngIf="!loading && !success" class="alert alert-danger">
              {{ message }}
            </div>

            <div class="mt-3">
              <a routerLink="/login" class="btn btn-primary">Go to Login</a>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
